import { Component } from '@angular/core';

@Component({
  selector: 'app-tab-navigation',
  template: `
    <div>
      <button (click)="selectTab('home')">Home</button>
      <button (click)="selectTab('profile')">Profile</button>
      <button (click)="selectTab('settings')">Settings</button>
      <div *ngIf="selectedTab === 'home'">Home content</div>
      <div *ngIf="selectedTab === 'profile'">Profile content</div>
      <div *ngIf="selectedTab === 'settings'">Settings content</div>
    </div>
  `
})
export class TabNavigationComponent {
  selectedTab = 'home';

  selectTab(tab: string) {
    this.selectedTab = tab;
  }
}
